script:
frappe.ui.form.on("Quotation", {
    onload: function(frm) {
        if (frm.is_new()) frappe.after_ajax(() => fill_missing_item_details(frm));
    },
    refresh: function(frm) {
        if (frm.is_new()) setTimeout(() => fill_missing_item_details(frm), 300);
    }
});

function fill_missing_item_details(frm) {
    var needs_fill = (frm.doc.items || []).filter(row => row.item_code && (!row.item_name || !row.uom));
    if (!needs_fill.length) return;
    needs_fill.forEach(function(item) {
        frm.script_manager.trigger("item_code", item.doctype, item.name);
    });
}

frappe.ui.form.on('Job File', {
    refresh: function(frm) {
        // 1. Check if the dashboard wrapper exists
        if (frm.dashboard && frm.dashboard.wrapper) {

            // 2. Locate our target HTML field (dashboard_html)
            var target_wrapper = frm.fields_dict['dashboard_html'].wrapper;

            // 3. Move the dashboard into the target field
            $(target_wrapper).empty().append(frm.dashboard.wrapper);

            // Optional: Hide the default section label if it looks messy
            $(target_wrapper).find('.section-head').hide();
        }
    }
});

frappe.ui.form.on("Technical Survey", {

    onload: function(frm) {
        if (frm.doc.custom_job_file && frm.is_new()) {
            fetch_job_file_data(frm);
        }
    },

    custom_job_file: function(frm) {
        if (!frm.doc.custom_job_file) return;
        fetch_job_file_data(frm);
    }

});


function fetch_job_file_data(frm) {

    frappe.db.get_value("Job File", frm.doc.custom_job_file, [
        "monthly_consumption",
        "existing_load_kw",
        "required_load_kw",
        "sanctioned_load_kw",
        "phase_type",
        "discom",
        "proposed_system",
        "roof_area_sqft",
        "roof_type",
        "site_type",
        "area_suitability",
        "preferred_visit_date",
        "preferred_time_slot"
    ]).then(r => {

        if (!r.message) return;

        let d = r.message;

        frm.set_value({
            monthly_consumption: d.monthly_consumption,
            existing_load_kw: d.existing_load_kw,
            required_load_kw: d.required_load_kw,
            sanctioned_load_kw: d.sanctioned_load_kw,
            discom: d.discom,
            phase_type_copy: d.phase_type,
            proposed_system_kw__tier: d.proposed_system,
            roof_area_sqft: d.roof_area_sqft,
            roof_type: d.roof_type,
            site_type: d.site_type,
            area_suitability: d.area_suitability,
            data_ycke: d.preferred_visit_date,
            data_tila: d.preferred_time_slot
        });

    });

}

// Solar EPC GST — INCLUSIVE price
// User enters final price (e.g. ₹100), system extracts tax from within it
// Net = EnteredPrice ÷ 1.089  |  Grand Total = EnteredPrice

var _adjusting = false;

frappe.ui.form.on('Quotation Item', {
    rate: function(frm, cdt, cdn) {
        if (_adjusting) return;
        var row = locals[cdt][cdn];
        if (!flt(row.rate)) return;

        var inclusive = flt(row.rate);
        var net = flt(inclusive / 1.089, 2);

        _adjusting = true;
        frappe.model.set_value(cdt, cdn, 'rate', net)
            .then(function() {
                return frappe.model.set_value(cdt, cdn, 'qty', flt(row.qty || 1));
            })
            .then(function() {
                setTimeout(function() {
                    _adjusting = false;
                    solar_fill_taxes(frm);
                }, 400);
            });
    },
    qty:          function(frm) { if (!_adjusting) solar_fill_taxes(frm); },
    items_remove: function(frm) { solar_fill_taxes(frm); }
});

frappe.ui.form.on('Quotation', {
    taxes_and_charges: function(frm) {
        setTimeout(function() { solar_fill_taxes(frm); }, 600);
    },
    refresh: function(frm) { solar_fill_taxes(frm); }
});

function solar_fill_taxes(frm) {
    if (!frm.doc.taxes || !frm.doc.items) return;

    var net = frm.doc.items.reduce(function(s, r) {
        return s + flt(r.amount || (flt(r.rate) * flt(r.qty || 1)));
    }, 0);
    if (!net) return;

    var tax_map = {
        'solar equipment cgst': flt(net * 0.70 * 0.025, 2),
        'solar equipment sgst': flt(net * 0.70 * 0.025, 2),
        'solar services cgst':  flt(net * 0.30 * 0.09,  2),
        'solar services sgst':  flt(net * 0.30 * 0.09,  2)
    };

    frm.doc.taxes.forEach(function(t) {
        var key = (t.description || '').toLowerCase().trim();
        if (tax_map.hasOwnProperty(key)) {
            frappe.model.set_value(t.doctype, t.name, 'tax_amount', tax_map[key]);
        }
    });

    frm.refresh_field('taxes');
}

